      },
      {
        "character_id": "C002",
        "name": "陈叔",
        "aliases": [],
        "role": "supporting",
        "description": null
      },
      {
        "character_id": "C003",
        "name": "周南",
        "aliases": [],
        "role": "supporting",
        "description": "站在巷口阴影中等待林砚，被质问"
      }
    ],
    "locations": [
      {
        "location_id": "L001",
        "name": "老街巷口",
        "aliases": [],
        "description": "雨夜，路灯下，门缝中夹着匿名信"
      },
      {
        "location_id": "L002",
        "name": "档案室",
        "aliases": [],
        "description": "灯坏了一半，只剩最里面一排冷白色的光"
      },
      {
        "location_id": "L003",
        "name": "巷口",
        "aliases": [],
        "description": "雨后路灯迟亮，地面反着碎光的巷口"
